import{_ as i,o as t,c as a,ak as e}from"./chunks/framework.DsiwUQoa.js";const b=JSON.parse('{"title":"📱 手机Root指南","description":"","frontmatter":{},"headers":[],"relativePath":"Help/Root/index.md","filePath":"Help/Root/index.md","lastUpdated":1782509372000}'),s={name:"Help/Root/index.md"};function l(r,o,n,d,g,c){return t(),a("div",null,[...o[0]||(o[0]=[e(`<h1 id="📱-手机root指南" tabindex="-1">📱 手机Root指南 <a class="header-anchor" href="#📱-手机root指南" aria-label="Permalink to “📱 手机Root指南”">​</a></h1><h2 id="⚠️-重要声明-请务必阅读" tabindex="-1">⚠️ 重要声明（请务必阅读） <a class="header-anchor" href="#⚠️-重要声明-请务必阅读" aria-label="Permalink to “⚠️ 重要声明（请务必阅读）”">​</a></h2><p>Root操作（获取最高系统权限）是一把双刃剑。它能让您完全掌控安卓设备，进行深度定制、卸载预装应用、运行高级工具等，但也伴随巨大风险：</p><ul><li><strong>失去官方保修：</strong> 多数厂商不为已Root设备提供保修。</li><li><strong>系统不稳定：</strong> 错误操作可能导致频繁死机、重启，甚至“变砖”。</li><li><strong>安全风险：</strong> 恶意软件可能更易入侵，窃取隐私信息。</li><li><strong>无法接收官方系统更新（OTA）：</strong> Root会修改系统分区，影响官方推送的系统更新。</li></ul><p><strong>请完整阅读本教程，理解每一步，并务必备份所有重要数据。因操作不当造成的任何损失，需自行承担！</strong></p><hr><h2 id="一、准备工作" tabindex="-1">一、准备工作 <a class="header-anchor" href="#一、准备工作" aria-label="Permalink to “一、准备工作”">​</a></h2><p>在Root前，请务必完成以下准备：</p><h3 id="_1-解锁bootloader" tabindex="-1">1. 解锁Bootloader <a class="header-anchor" href="#_1-解锁bootloader" aria-label="Permalink to “1. 解锁Bootloader”">​</a></h3><ul><li><strong>什么是Bootloader？</strong> 安卓系统启动前的引导程序，厂商默认锁定以防止系统被修改。</li><li><strong>为何要解锁？</strong> 只有解锁后，才能刷入第三方镜像（如修补后的<code>boot.img</code>或TWRP Recovery）。</li><li><strong>如何解锁？</strong> 不同品牌方式不同（如小米需官方工具，OPPO/Realme需深度测试等）。请查阅品牌官方指南或XDA-Developers等社区。<br><strong>注意：</strong> 解锁Bootloader会清除所有数据，请提前备份！</li></ul><h3 id="_2-下载必要文件与工具" tabindex="-1">2. 下载必要文件与工具 <a class="header-anchor" href="#_2-下载必要文件与工具" aria-label="Permalink to “2. 下载必要文件与工具”">​</a></h3><ul><li><strong>Platform-Tools (ADB &amp; Fastboot)：</strong> Google官方命令行工具，用于电脑与手机间高级通信。 <ul><li><strong>官方下载：</strong> <a href="https://developer.android.com/tools/releases/platform-tools" target="_blank" rel="noreferrer">SDK Platform Tools release notes</a></li><li><strong>使用方法：</strong> 下载对应系统的压缩包，解压到<strong>不含中文或特殊字符</strong>的路径（如 <code>C:\\adb</code>），后续命令行操作均在此文件夹内进行。 <ul><li><strong>ADB (Android Debug Bridge)：</strong> 用于与安卓设备通信，可以执行各种设备管理命令。</li><li><strong>Fastboot：</strong> 用于在设备处于Fastboot模式时进行低级操作，如刷写分区。</li></ul></li></ul></li><li><strong>手机官方固件（ROM）：</strong> 下载与当前系统版本<strong>完全一致</strong>的ROM包，用于提取修补所需的<code>boot.img</code>或<code>init_boot.img</code>。可在手机官网或可信ROM资源站获取。</li><li><strong>Magisk App：</strong> 目前主流Root方案，具备“systemless”特性。请从官方GitHub发布页下载最新版Magisk App（<code>.apk</code>文件）。</li></ul><hr><h2 id="二、root核心操作" tabindex="-1">二、Root核心操作 <a class="header-anchor" href="#二、root核心操作" aria-label="Permalink to “二、Root核心操作”">​</a></h2><p>本教程推荐两种主流Magisk Root方法，<strong>方法一最通用且推荐！</strong></p><h3 id="方法一-修补启动镜像-boot-img-init-boot-img" tabindex="-1">方法一：修补启动镜像（boot.img / init_boot.img） <a class="header-anchor" href="#方法一-修补启动镜像-boot-img-init-boot-img" aria-label="Permalink to “方法一：修补启动镜像（boot.img / init_boot.img）”">​</a></h3><p><strong>Magisk官方推荐，兼容性最佳。</strong></p><h4 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to “核心概念”">​</a></h4><ul><li><code>boot.img</code>：包含系统内核和Ramdisk，是安卓启动关键。</li><li><code>init_boot.img</code>：Android 13及以上设备，Ramdisk被移至独立<code>init_boot</code>分区。</li><li><strong>判断标准：</strong> 安装并打开Magisk，主界面会显示“Ramdisk”状态。若需修补<code>init_boot.img</code>，会有提示或需根据内核版本判断。一般2022年后新机型多用<code>init_boot.img</code>。</li></ul><h4 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>提取启动镜像：</strong> 解压官方ROM包，找到<code>boot.img</code>或<code>init_boot.img</code>。</li><li><strong>传输镜像到手机：</strong> 将上述文件复制到手机内部存储（如“下载”文件夹）。</li><li><strong>安装Magisk应用：</strong> 在手机安装Magisk <code>.apk</code>。</li><li><strong>修补镜像文件：</strong><ul><li>打开Magisk，点击“安装”</li><li>选择“选择并修补一个文件”</li><li>选择刚复制的<code>boot.img</code>或<code>init_boot.img</code></li><li>修补完成后在“下载”文件夹生成<code>magisk_patched-版本号.img</code></li></ul></li><li><strong>传输已修补镜像到电脑：</strong> 将<code>magisk_patched-....img</code>复制回电脑<code>platform-tools</code>文件夹。</li><li><strong>进入Fastboot模式：</strong> 手机关机，同时按“电源键+音量下键”（部分品牌组合键不同）至Fastboot/Bootloader界面。</li><li><strong>连接电脑并刷入：</strong><ul><li>用USB线连接手机至电脑。</li><li>在<code>platform-tools</code>文件夹内，地址栏输入<code>cmd</code>或<code>powershell</code>回车，打开命令行。</li><li>输入：<div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fastboot devices</span></span></code></pre></div>若显示序列号，说明连接成功。</li><li><strong>根据修补文件类型，执行：</strong><ul><li>修补<code>boot.img</code>：<div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fastboot flash boot magisk_patched-....img</span></span></code></pre></div></li><li>修补<code>init_boot.img</code>：<div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fastboot flash init_boot magisk_patched-....img</span></span></code></pre></div></li></ul><em>(请将文件名替换为实际生成的文件名)</em></li></ul></li><li><strong>重启手机：</strong><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fastboot reboot</span></span></code></pre></div></li><li><strong>完成：</strong> 开机后打开Magisk，若显示当前版本号即Root成功！</li></ol><blockquote><p><strong>提示：</strong> 如果您不确定应该使用 <code>boot.img</code> 还是 <code>init_boot.img</code>，可以打开Magisk应用，在主界面查看“Ramdisk”状态。如果显示“无Ramdisk”，则需要修补 <code>init_boot.img</code>。</p></blockquote><hr><h3 id="方法二-通过第三方recovery刷入magisk" tabindex="-1">方法二：通过第三方Recovery刷入Magisk <a class="header-anchor" href="#方法二-通过第三方recovery刷入magisk" aria-label="Permalink to “方法二：通过第三方Recovery刷入Magisk”">​</a></h3><p>如已刷入第三方Recovery（如TWRP），可用此法。</p><h4 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to “前提条件”">​</a></h4><ul><li>手机已成功刷入可用第三方Recovery（TWRP/OrangeFox等）。</li></ul><h4 id="操作步骤-1" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-1" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>准备文件：</strong> 下载Magisk <code>.apk</code>，重命名为<code>Magisk.zip</code>，复制到手机存储或SD卡。</li><li><strong>进入Recovery模式：</strong> 重启至TWRP等第三方Recovery（按键组合因机型而异）。</li><li><strong>刷入Magisk：</strong><ul><li>TWRP主界面点击“Install”。</li><li>选择<code>Magisk.zip</code>。</li><li>滑动滑块确认刷入。</li></ul></li><li><strong>重启系统：</strong> 刷入完成后选择“Reboot System”。</li><li><strong>完成：</strong> 重启后桌面会出现Magisk图标，若无可手动安装<code>.apk</code>。</li></ol><blockquote><p><strong>提示：</strong> 刷入Magisk后，建议立即重启手机，以确保Magisk正确加载。</p></blockquote><hr><h2 id="三、紧急情况与卸载" tabindex="-1">三、紧急情况与卸载 <a class="header-anchor" href="#三、紧急情况与卸载" aria-label="Permalink to “三、紧急情况与卸载”">​</a></h2><h3 id="刷入后无法开机" tabindex="-1">刷入后无法开机？ <a class="header-anchor" href="#刷入后无法开机" aria-label="Permalink to “刷入后无法开机？”">​</a></h3><p>如Root后卡在开机动画或无法进入系统，通常因镜像不匹配。只需重新进入Fastboot模式，刷回官方ROM中提取的<strong>原始</strong><code>boot.img</code>或<code>init_boot.img</code>即可：</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fastboot flash boot boot.img        # 刷回原始boot.img</span></span>
<span class="line"><span>fastboot flash init_boot init_boot.img  # 刷回原始init_boot.img</span></span></code></pre></div><blockquote><p><strong>提示：</strong> 如果您没有原始的 <code>boot.img</code> 或 <code>init_boot.img</code>，可以尝试重新下载与当前系统版本完全一致的官方ROM包，并从中提取。</p></blockquote><h3 id="如何卸载magisk" tabindex="-1">如何卸载Magisk？ <a class="header-anchor" href="#如何卸载magisk" aria-label="Permalink to “如何卸载Magisk？”">​</a></h3><p>最简单方法：打开Magisk应用，首页下方有“卸载Magisk”选项，点击后选择“完全卸载”即可。</p><blockquote><p><strong>提示：</strong> 卸载Magisk后，您可能需要手动删除一些由Magisk模块创建的文件或文件夹，以确保系统完全恢复到未Root状态。</p></blockquote><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>通过本教程，您应该已经了解了如何使用Magisk对安卓设备进行Root操作。请务必谨慎操作，并在操作前备份所有重要数据。Root操作虽然能带来强大的功能，但也伴随着风险。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to “参考资料”">​</a></h2><ul><li><a href="https://github.com/topjohnwu/Magisk" target="_blank" rel="noreferrer">Magisk官方GitHub仓库</a></li><li><a href="https://forum.xda-developers.com/" target="_blank" rel="noreferrer">XDA-Developers论坛</a></li><li><a href="https://developer.android.com/tools/adb" target="_blank" rel="noreferrer">Android开发者官方文档 - ADB</a></li><li><a href="https://developer.android.com/tools/fastboot" target="_blank" rel="noreferrer">Android开发者官方文档 - Fastboot</a></li></ul>`,44)])])}const p=i(s,[["render",l]]);export{b as __pageData,p as default};
